import { computed, defineComponent, onMounted, ref, shallowRef } from 'vue';
import { store } from '../../store';
import CharacterApp from '../../views/apps/CharacterApp.vue';
import MapApp from '../../views/apps/MapApp.vue';
import DestinyCardPanel from '../panels/DestinyCardPanel.vue';
import DiaryPanel from '../panels/DiaryPanel.vue';
import ForumPanel from '../panels/ForumPanel.vue';
import InventoryPanel from '../panels/InventoryPanel.vue';
import NpcDirectoryPanel from '../panels/NpcDirectoryPanel.vue';
import SystemPanel from '../panels/SystemPanel.vue';
import TimelinePanel from '../panels/TimelinePanel.vue';
import AppViewContainer from './AppViewContainer.vue';
import HomeScreen from './HomeScreen.vue';
const apps = {
    contacts: NpcDirectoryPanel,
    calendar: TimelinePanel,
    character: CharacterApp,
    destiny: DestinyCardPanel,
    diary: DiaryPanel,
    inventory: InventoryPanel,
    forum: ForumPanel,
    map: MapApp,
    system: SystemPanel,
};
export default defineComponent({
    name: 'SmartphoneShell',
    components: { HomeScreen, AppViewContainer },
    emits: ['close-smartphone'],
    setup() {
        const activeAppId = ref(null);
        const activeApp = shallowRef(null);
        const isDiaryNavOpen = ref(false);
        const getAppName = (id) => {
            const appMap = {
                contacts: '通讯录',
                calendar: '日历',
                character: '角色',
                destiny: '命运',
                diary: '日记',
                forum: '论坛',
                system: '系统',
                map: '地图',
                inventory: '背包',
            };
            return appMap[id] || '应用';
        };
        const openApp = (appId) => {
            if (apps[appId]) {
                activeApp.value = apps[appId];
                activeAppId.value = appId;
                if (appId !== 'diary') {
                    isDiaryNavOpen.value = false;
                }
            }
            else {
                console.warn(`App not found: ${appId}`);
                activeApp.value = null;
                activeAppId.value = appId;
            }
        };
        const goHome = () => {
            activeAppId.value = null;
            activeApp.value = null;
            isDiaryNavOpen.value = false;
        };
        const currentTime = ref('');
        const updateTime = () => {
            const now = new Date();
            currentTime.value = now.toTimeString().slice(0, 5);
        };
        onMounted(() => {
            updateTime();
            setInterval(updateTime, 1000 * 60);
        });
        const batteryLevel = computed(() => {
            const worldState = store.worldState?.世界状态;
            if (!worldState?.行动点 || !worldState?.时间)
                return 100;
            // 从神谕引擎获取权威的时间片段定义和AP预算
            const segmentAPMap = {
                清晨: 6,
                上午前: 6,
                上午: 6,
                午休: 8,
                下午: 6,
                下午后: 10,
                夜晚: 6,
            };
            const segments = ['清晨', '上午前', '上午', '午休', '下午', '下午后', '夜晚'];
            const totalApPerDay = Object.values(segmentAPMap).reduce((sum, ap) => sum + ap, 0);
            const currentSegment = worldState.时间.当前片段;
            const currentSegmentIndex = segments.indexOf(currentSegment);
            const currentAP = worldState.行动点.当前;
            if (currentSegmentIndex === -1) {
                console.error(`未知的当前时间片段: ${currentSegment}`);
                return 100; // 返回一个安全值
            }
            // 计算当天到当前片段为止，已经消耗的总AP
            let apSpentToday = 0;
            for (let i = 0; i < currentSegmentIndex; i++) {
                apSpentToday += segmentAPMap[segments[i]];
            }
            // 加上当前片段已经消耗的AP
            const currentSegmentBudget = segmentAPMap[currentSegment];
            apSpentToday += currentSegmentBudget - currentAP;
            if (totalApPerDay === 0)
                return 100;
            const percentage = 100 - Math.round((apSpentToday / totalApPerDay) * 100);
            return Math.max(0, Math.min(100, percentage));
        });
        const batteryIcon = computed(() => {
            if (batteryLevel.value > 80)
                return 'fa-battery-full';
            if (batteryLevel.value > 60)
                return 'fa-battery-three-quarters';
            if (batteryLevel.value > 40)
                return 'fa-battery-half';
            if (batteryLevel.value > 10)
                return 'fa-battery-quarter';
            return 'fa-battery-empty';
        });
        return {
            activeAppId,
            activeApp,
            openApp,
            goHome,
            getAppName,
            currentTime,
            batteryLevel,
            batteryIcon,
            isDiaryNavOpen,
        };
    },
});
